    fn readdir(
        &mut self,
        _req: &Request<'_>,
        ino: u64,
        _fh: u64,
        offset: i64,
        mut reply: ReplyDirectory,
    ) {
        let entries = self.fs.listdir(ino as u32);
        match entries {
            Ok(entries) => {
                let mut i = offset as usize;
                while i < entries.len() {
                    let entry = &entries[i];
                    if reply.add(
                        ino,
                        i as i64 + 1,
                        translate_ftype(self.fs.getattr(entry.inode()).unwrap().ftype),
                        entry.name(),
                    ) {
                        break;
                    }
                    i += 1;
                }
                reply.ok();
            }
            Err(e) => {
                reply.error(e.code() as i32);
            }
        }
    }

