                if size == 0 {
                    reply.size(buffer.len() as u32);
                } else if buffer.len() <= size as usize {
                    reply.data(&buffer);
                } else {
                    reply.error(ErrCode::ERANGE as i32);
                }
            }
            Err(e) => reply.error(e.code() as i32),
        }
    }
