struct TimespecNs {
    tv_sec: i64,
    tv_nsec: i64,
}

pub async fn do_clock_nanosleep(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [clockid, flags, req_ptr, rem_ptr, ..] = uc.syscall_arguments();
    let _clockid = clockid as i32; // 0: REALTIME, 1: MONOTONIC；此处统一使用单调时钟
    let flags = flags as i32;
    if req_ptr == 0 {
        return Err(errno_with_message(Errno::EINVAL, "null req timespec"));
    }
    let req = state
        .process_vm
        .read_val::<TimespecNs>(req_ptr as _)
        .map_err(|_| errno_with_message(Errno::EFAULT, "bad timespec pointer"))?;
    if req.tv_nsec < 0 || req.tv_nsec >= 1_000_000_000 {
        return Err(errno_with_message(Errno::EINVAL, "invalid tv_nsec"));
    }

    if flags & TIMER_ABSTIME != 0 {
        // 绝对时间：若已到达或超时，直接返回 0；否则睡到目标
        let now = duration_since_boot();
        let target = Duration::from_secs(req.tv_sec as u64) + Duration::from_nanos(req.tv_nsec as u64);
        if target > now {
            let delta = target - now;
            sleep(delta).await;
        }
        // 成功路径忽略 remain；若需要，可写 0
        return Ok(ControlFlow::Continue(Some(0)));
    } else {
        // 相对时间
        let dur = Duration::from_secs(req.tv_sec as u64) + Duration::from_nanos(req.tv_nsec as u64);
        sleep(dur).await;
        return Ok(ControlFlow::Continue(Some(0)));
    }
}

