            zero()
        ))?
    };

    Ok(unsafe { cvt_waitid_status(status) })
}

unsafe fn cvt_waitid_status(status: MaybeUninit<c::siginfo_t>) -> Option<WaitIdStatus> {
    let status = status.assume_init();
    if status
        .__bindgen_anon_1
        .__bindgen_anon_1
        ._sifields
        ._sigchld
        ._pid
        == 0
    {
        None
    } else {
        Some(WaitIdStatus(status))
    }
}

