        self.pos.fetch_sub(len, Ordering::Relaxed);
        let pos = self.pos();
        self.vmo.write_bytes(pos - self.map_addr, bytes).map_err(ostd_error_to_errno)?;
        Ok(pos as u64)
    }

fn pos(&self) -> Vaddr {
        self.pos.load(Ordering::Relaxed)
    }

