pub fn allocate_memory_32(&mut self, size: u32) -> u32 {
        assert!(size.is_power_of_two());
        let allocated_address = align_up(self.start, size);
        assert!(allocated_address + size <= self.end);
        self.start = allocated_address + size;
        allocated_address
    }

const fn align_up(value: u32, alignment: u32) -> u32 {
    ((value - 1) | (alignment - 1)) + 1
}

fn dump_bar_contents(
    root: &mut PciRoot<impl ConfigurationAccess>,
    device_function: DeviceFunction,
    bar_index: u8,
) {
    let bar_info = root.bar_info(device_function, bar_index).unwrap();
    trace!("Dumping bar {}: {:#x?}", bar_index, bar_info);
    if let Some(BarInfo::Memory { address, size, .. }) = bar_info {
        let start = address as *const u8;
        unsafe {
            let mut buf = [0u8; 32];
            for i in 0..size / 32 {
                let ptr = start.add(i as usize * 32);
                ptr::copy(ptr, buf.as_mut_ptr(), 32);
                if buf.iter().any(|b| *b != 0xff) {
                    trace!("  {:?}: {:x?}", ptr, buf);
                }
            }
        }
    }
    trace!("End of dump");
}

fn allocate_bars(
    root: &mut PciRoot<impl ConfigurationAccess>,
    device_function: DeviceFunction,
    allocator: &mut PciMemory32Allocator,
) {
    for (bar_index, info) in root.bars(device_function).unwrap().into_iter().enumerate() {
        let Some(info) = info else { continue };
        debug!("BAR {}: {}", bar_index, info);
        // Ignore I/O bars, as they aren't required for the VirtIO driver.
        if let BarInfo::Memory {
            address_type, size, ..
        } = info
        {
            // For now, only attempt to allocate 32-bit memory regions.
            if size > u32::MAX.into() {
                warn!("Skipping BAR {} with size {:#x}", bar_index, size);
                continue;
            }
            let size = size as u32;

            match address_type {
                MemoryBarType::Width32 => {
                    if size > 0 {
                        let address = allocator.allocate_memory_32(size);
                        debug!("Allocated address {:#010x}", address);
                        root.set_bar_32(device_function, bar_index as u8, address);
                    }
                }
                MemoryBarType::Width64 => {
                    if size > 0 {
                        let address = allocator.allocate_memory_32(size);
                        debug!("Allocated address {:#010x}", address);
                        root.set_bar_64(device_function, bar_index as u8, address.into());
                    }
                }

                _ => panic!("Memory BAR address type {:?} not supported.", address_type),
            }
        }
    }

    // Enable the device to use its BARs.
    root.set_command(
        device_function,
        Command::IO_SPACE | Command::MEMORY_SPACE | Command::BUS_MASTER,
    );
    let (status, command) = root.get_status_command(device_function);
    debug!(
        "Allocated BARs and enabled device, status {:?} command {:?}",
        status, command
    );
}

fn panic(info: &PanicInfo) -> ! {
    error!("{}", info);
    system_off::<Hvc>().unwrap();
    loop {}
}

fn trap_handler(isf: InterruptStackFrame, index: u8, error_code: Option<u64>) {
    match index {
        x if x == ExceptionVector::Page as u8 => {
            let cr2 = x86_64::registers::control::Cr2::read();
            panic!(
                "#PF at {:#x}, fault_vaddr={:#x}, err_code={:#x?}",
                isf.instruction_pointer, cr2, error_code
            );
        }
        _ => {
            panic!(
                "Unhandled exception {} (error_code = {:#x?}) at {:#x}:\n{:#x?}",
                index, error_code, isf.instruction_pointer, isf
            );
        }
    }
}

pub fn init() {
    unsafe {
        set_general_handler!(&mut IDT, trap_handler);
        IDT.load();
    }
}

unsafe fn init_boot_page_table() {
    unsafe {
        let l1_va = va!(&raw const BOOT_PT_L1 as usize);
        // 0x0000_0000_0000 ~ 0x0080_0000_0000, table
        BOOT_PT_L0[0] = LA64PTE::new_table(crate::mem::virt_to_phys(l1_va));
        // 0x0000_0000..0x4000_0000, VPWXGD, 1G block
        BOOT_PT_L1[0] = LA64PTE::new_page(
            pa!(0),
            MappingFlags::READ | MappingFlags::WRITE | MappingFlags::DEVICE,
            true,
        );
        // 0x8000_0000..0xc000_0000, VPWXGD, 1G block
        BOOT_PT_L1[2] = LA64PTE::new_page(
            pa!(0x8000_0000),
            MappingFlags::READ | MappingFlags::WRITE | MappingFlags::EXECUTE,
            true,
        );
    }
}

unsafe fn init_mmu() {
    crate::arch::init_tlb();

    let paddr = crate::mem::virt_to_phys(va!(&raw const BOOT_PT_L0 as usize));
    pgdh::set_base(paddr.as_usize());
    pgdl::set_base(0);
    flush_tlb(None);
    crmd::set_pg(true);
}

struct Args {
    /// Fs mount point
    #[arg(short, long)]
    mountpoint: String,
    /// Load initial image
    #[arg(short, long)]
    image: Option<String>,
    /// Fs total block number, ignored when [image] is set
    #[arg(short, long, default_value_t = 8192)]
    block: u64,
    /// Save image on exit
    #[arg(short, long)]
    output: Option<String>,
    /// Log level
    #[arg(short, long, default_value_t = String::from("info"))]
    log: String,
}

fn parse_log_level(level_str: &str) -> LevelFilter {
    match level_str.to_lowercase().as_str() {
        "off" => LevelFilter::Off,
        "error" => LevelFilter::Error,
        "warn" => LevelFilter::Warn,
        "info" => LevelFilter::Info,
        "debug" => LevelFilter::Debug,
        "trace" => LevelFilter::Trace,
        _ => LevelFilter::Off,
    }
}

fn main() {
    let args = Args::parse();

    // Initialize logger
    println!("Log level {}", args.log);
    SimpleLogger::new().init().unwrap();
    log::set_max_level(parse_log_level(&args.log));

    // Initialize block device and filesystem
    let block_mem = if let Some(image) = &args.image {
        println!("Load image {}", image);
        Arc::new(BlockMem::load(&image))
    } else {
        println!("Create disk image with {} blocks", args.block);
        let block_mem = Arc::new(BlockMem::new(args.block));
        block_mem.mkfs();
        block_mem
    };
    // Create filesystem and init if image is newly created
    let fs = StateExt4FuseFs::new(block_mem.clone(), args.image.is_none());

    // Mount fs and enter session loop
    println!("Mount ext4fs to {}", args.mountpoint);
    let options = Vec::<MountOption>::new();
    let session =
        fuser::spawn_mount2(fs, &args.mountpoint, &options).expect("Failed to start FUSE session");

    // Set EXIT_FLAG when Ctrl+C is received
    let _ = ctrlc::set_handler(|| {
        EXIT_FLAG.get_or_init(|| true);
    });
    // Loop until EXIT_FLAG is set
    loop {
        if EXIT_FLAG.get().is_some() {
            println!("Received Ctrl+C, exiting...");
            if let Some(output) = &args.output {
                println!("Save image {}", output);
                block_mem.save(output);
            }
            break;
        }
    }
    session.join();
}

pub struct ProcessVm {
    root_vmar: Vmar<Full>,
    heap: Heap,
    init_stack: InitStack,  
}

impl ProcessVm {
    /// Allocates a new `ProcessVm`
    pub async fn alloc() -> Self {
        let root_vmar = Vmar::<Full>::new_root();
