pub fn task_future(mut thread_state: ThreadState) -> impl Future<Output = ()> + Send + 'static {
    async move {
        let current = &thread_state.task;
        {
            let disable_preempt = disable_preempt();
            let cpu_id = disable_preempt.current_cpu().as_usize();
            info!("用户任务开始在CPU {} 上执行", cpu_id);
        }
        let user_space = current.user_space().unwrap().clone();
        let mut user_mode = UserMode::new(&user_space);
        info!("创建用户模式完成，准备进入用户空间");
        let current_id = thread_state.shared_info.tid;

        let code = loop {
            // The execute method returns when system
            // calls or CPU exceptions occur or some
            // events specified by the kernel occur.
            debug!("准备切换到用户空间执行: {}", current_id);
            let return_reason = user_mode.execute(|| false).await;
            debug!("从用户空间返回，原因: {:?} 线程id: {}", return_reason, current_id);

            // The CPU registers of the user space
            // can be accessed and manipulated via
            // the `UserContext` abstraction.
            let user_context = user_mode.context_mut();
            if return_reason == ReturnReason::UserException {
                if user_context.trap_information().code == CpuException::UserEnvCall {
                    let syscall_number = user_context.syscall_number() as i64;
                    debug!("处理系统调用，系统调用号: {}， {}", syscall_number, sys_call_name(syscall_number).unwrap_or("unknown"));
                    let res = syscall(&mut thread_state, user_context).await;
                    match res {
                        Ok(ControlFlow::Continue(Some(ret))) => {
                            tracing::info!("系统调用返回值: {}", ret);
                            user_context.set_syscall_return_value(ret as _);
                        }
                        Ok(ControlFlow::Continue(None)) => {}
                        Ok(ControlFlow::Break(code)) => {
                            break code;
                        }
                        Err(e) => {
                            error!("系统调用失败: {:?}", e);
                            let ret = e.downcast_ref::<Error>().map(|e| -(e.error() as isize)).unwrap_or(-1);
                            user_context.set_syscall_return_value(ret as _);
                        }
                    }
                } else {
                    debug!("处理异常");
                    if let Ok(page_fault_info) =
                        PageFaultInfo::try_from(user_context.trap_information())
                    {
                        if handle_page_fault_from_vmar(
                            &thread_state.process_vm.root_vmar(),
                            &page_fault_info,
                        )
                        .block()
                        .is_err() {
                            error!("处理页错误失败");
                        }
                    }
                }
            }
        };
        // 在用户 loop 跳出（正常或错误）后，进行收尾
        thread_state.shared_info.lifecycle.exit(code);
    }
}

struct Rlimit64 {
    rlim_cur: u64,
    rlim_max: u64,
}

pub async fn do_prlimit64(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [_pid, _resource, new_ptr, old_ptr, ..] = uc.syscall_arguments();
    if new_ptr != 0 {
        // 接受但忽略（最小实现）
        let _ = state
            .process_vm
            .read_val::<Rlimit64>(new_ptr as _)
            .map_err(|_| errno_with_message(Errno::EFAULT, "bad new rlimit ptr"))?;
    }
    if old_ptr != 0 {
        let inf = Rlimit64 { rlim_cur: RLIM_INFINITY, rlim_max: RLIM_INFINITY };
        state
            .process_vm
            .write_val(old_ptr as _, &inf)
            .map_err(|_| errno_with_message(Errno::EFAULT, "bad old rlimit ptr"))?;
    }
    Ok(ControlFlow::Continue(Some(0)))
}

fn xorshift64(mut x: u64) -> u64 {
    x ^= x << 13;
    x ^= x >> 7;
    x ^= x << 17;
    x
}

pub async fn do_getrandom(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [buf_ptr, buflen, _flags, ..] = uc.syscall_arguments();
    if buf_ptr == 0 {
        return Err(errno_with_message(Errno::EFAULT, "null buffer"));
    }
    let len = buflen as usize;
    if len == 0 {
        return Ok(ControlFlow::Continue(Some(0)));
    }
    // 以 jiffies + tid + 指针混合作种子（弱随机）
    let mut s = ostd::timer::Jiffies::elapsed().as_u64()
        ^ (state.shared_info.tid as u64)
        ^ (buf_ptr as u64);
    let mut out = vec![0u8; len];
    let mut i = 0;
    while i < len {
        s = xorshift64(s);
        out[i] = (s & 0xFF) as u8;
        i += 1;
    }
    state
        .process_vm
        .write_bytes(buf_ptr, &mut ostd::mm::VmReader::from(out.as_slice()))?;
    Ok(ControlFlow::Continue(Some(len as isize)))
}

pub async fn do_set_robust_list(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [head_ptr, len, ..] = uc.syscall_arguments();
    // glibc会传入 sizeof(struct robust_list_head)；此处仅做基本校验
    if head_ptr == 0 {
        return Err(errno_with_message(Errno::EINVAL, "robust_list head is NULL"));
    }
    if len == 0 {
        return Err(errno_with_message(Errno::EINVAL, "robust_list length is zero"));
    }
    state.robust_list_head = head_ptr as usize;
    state.robust_list_len = len as usize;
    Ok(ControlFlow::Continue(Some(0)))
}

pub async fn do_get_robust_list(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [pid, head_ptr_ptr, len_ptr, ..] = uc.syscall_arguments();
    // 仅支持 pid == 0（当前线程）
    if pid != 0 {
        return Err(errno_with_message(Errno::ESRCH, "only current thread supported"));
    }
    if head_ptr_ptr == 0 || len_ptr == 0 {
        return Err(errno_with_message(Errno::EFAULT, "invalid user pointers"));
    }
    let head = state.robust_list_head as u64;
    let len = state.robust_list_len as u64;
    state
        .process_vm
        .write_val(head_ptr_ptr as _, &head)?;
    state
        .process_vm
        .write_val(len_ptr as _, &len)?;
    Ok(ControlFlow::Continue(Some(0)))
}

struct KernelSigaction {
    handler: usize,
    flags: u64,
    restorer: usize,
    mask: KernelSigset,
}

pub async fn do_rt_sigprocmask(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [how, set_ptr, oldset_ptr, sigsetsize, ..] = uc.syscall_arguments();
    // 允许sigsetsize为8或16，仅处理低64位
    if sigsetsize == 0 {
        return Err(errno_with_message(Errno::EINVAL, "invalid sigsetsize"));
    }
    // 返回旧mask
    if oldset_ptr != 0 {
        let old = KernelSigset(state.sig_mask);
        state.process_vm.write_val(oldset_ptr as _, &old)?;
    }
    // 应用新mask
    if set_ptr != 0 {
        let new = state.process_vm.read_val::<KernelSigset>(set_ptr as _)?;
        match how as i32 {
            // SIG_BLOCK: union
            0 => state.sig_mask |= new.0,
            // SIG_UNBLOCK: remove
            1 => state.sig_mask &= !new.0,
            // SIG_SETMASK: set
            2 => state.sig_mask = new.0,
            _ => return Err(errno_with_message(Errno::EINVAL, "invalid how")),
        }
    }
    Ok(ControlFlow::Continue(Some(0)))
}

pub async fn do_rt_sigaction(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [_signum, act_ptr, oldact_ptr, sigsetsize, ..] = uc.syscall_arguments();
    if sigsetsize == 0 {
        return Err(errno_with_message(Errno::EINVAL, "invalid sigsetsize"));
    }
    // 如调用方请求 oldact，返回全零（默认动作），避免 ENOSYS
    if oldact_ptr != 0 {
        let zero = KernelSigaction::default();
        state
            .process_vm
            .write_val(oldact_ptr as _, &zero)
            .map_err(|_| errno_with_message(Errno::EFAULT, "invalid sigaction pointer"))?;
    }
    // 接受 act 但不存储（最小实现）
    if act_ptr != 0 {
        let _ = state
            .process_vm
            .read_val::<KernelSigaction>(act_ptr as _)
            .map_err(|_| errno_with_message(Errno::EFAULT, "invalid sigaction pointer"))?;
    }
    Ok(ControlFlow::Continue(Some(0)))
}

