impl Utsname {
    fn current() -> Self {
        const SYSNAME:     &str = "NexusOS";
        const NODENAME:    &str = "localhost";
        // 为兼容 glibc，报告一个现代内核版本，避免 "FATAL: kernel too old"
        const RELEASE:     &str = "5.10.0";
        const VERSION:     &str = "5.10.0-NexusOS";
        #[cfg(target_arch = "riscv64")]
        const MACHINE:     &str = "riscv64";
        #[cfg(target_arch = "x86_64")]
        const MACHINE:     &str = "x86_64";
        #[cfg(target_arch = "loongarch64")]
        const MACHINE:     &str = "loongarch64";
        #[cfg(not(any(target_arch = "riscv64", target_arch = "x86_64", target_arch = "loongarch64")))]
        const MACHINE:     &str = "unknown";
        const DOMAINNAME:  &str = "";

        fn fill(src: &str) -> [u8; UTS_LEN] {
            let mut buf = [0u8; UTS_LEN];
            let bytes = src.as_bytes();
            let len = bytes.len().min(UTS_LEN - 1); // 预留结尾 \0
            buf[..len].copy_from_slice(&bytes[..len]);
            buf
        }

        Self {
            sysname:    fill(SYSNAME),
            nodename:   fill(NODENAME),
            release:    fill(RELEASE),
            version:    fill(VERSION),
            machine:    fill(MACHINE),
            domainname: fill(DOMAINNAME),
        }
    }
}

