pub async fn do_uname(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [buf_ptr, ..] = uc.syscall_arguments();
    if buf_ptr == 0 {
        return Err(errno_with_message(Errno::EFAULT, "buf is NULL"));
    }

    // 写入用户缓冲区；内部包含完整越界/页故障检测
    state
        .process_vm
        .write_val(buf_ptr as _, &Utsname::current())?;

    Ok(ControlFlow::Continue(Some(0)))
}

struct TimespecNs {
    tv_sec: i64,
    tv_nsec: i64,
}

pub async fn do_nanosleep(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let req_time = uc.syscall_arguments()[0] as usize;
    let _rem_time = uc.syscall_arguments()[1] as usize;

    if req_time == 0 {
        return Err(errno_with_message(Errno::EINVAL, "invalid time"));
    }

    let vm = &state.process_vm;
    let req = vm
        .read_val::<TimespecNs>(req_time as _)
        .map_err(|_| errno_with_message(Errno::EFAULT, "invalid time"))?;

    // 校验纳秒范围
    if req.tv_nsec < 0 || req.tv_nsec >= 1_000_000_000 {
        return Err(errno_with_message(Errno::EINVAL, "invalid tv_nsec"));
    }

    let req_time = Duration::from_secs(req.tv_sec as u64)
        + Duration::from_nanos(req.tv_nsec as u64);

    sleep(req_time).await;

    Ok(ControlFlow::Continue(Some(0)))
}

