pub fn crc32(crc_init: u32, data: &[u8]) -> u32 {
    let mut crc = crc_init;
    for byte in data {
        crc = CRC32C_TAB[(crc as u8 ^ byte) as usize] ^ (crc >> 8);
    }
    crc
}

