pub struct DentryCache {
    // 键是目录路径和文件名的组合，值是对应的Vnode
    cache: RwLock<HashMap<(PathBuf, AllocString), SVnode>>,
    capacity: usize, // 缓存容量上限
}

impl DentryCache {
    /// 创建一个新的DentryCache实例
    ///
    /// # 参数
    /// - `capacity`: 缓存的预期容量
    pub fn new(capacity: usize) -> Self {
        Self {
            cache: RwLock::new(HashMap::new()), // BTreeMap没有with_capacity方法
            capacity,
        }
    }

    /// 获取缓存中的目录项
    ///
    /// # 参数
    /// - `dir_path`: 父目录路径
    /// - `name`: 文件或目录名
    ///
    /// # 返回
    /// 如果找到，返回缓存的Vnode；否则返回None
    pub async fn get(
        &self,
        dir_path: &PathBuf,
        name: &str,
    ) -> Option<SVnode> {
        let cache = self.cache.read().await;
        cache
            .get(&(dir_path.clone(), AllocString::from(name)))
            .cloned()
    }

    /// 向缓存中添加目录项
    ///
    /// # 参数
    /// - `dir_path`: 父目录路径
    /// - `name`: 文件或目录名
    /// - `vnode`: 对应的Vnode
    pub async fn put(
        &self,
        dir_path: PathBuf,
        name: &str,
        vnode: SVnode,
    ) {
        let mut cache = self.cache.write().await;

        // 如果缓存满了，可以实现一个淘汰策略
        // 目前为简化实现，如果容量超限，不添加新项
        if cache.len() >= self.capacity {
            return;
        }

        cache.insert((dir_path, AllocString::from(name)), vnode);
    }

    /// 清除与特定目录相关的所有缓存项
    ///
    /// 当目录内容变化时调用此方法
    ///
    /// # 参数
    /// - `dir_path`: 被修改的目录路径
    pub async fn invalidate_dir(&self, dir_path: &PathBuf) {
        let mut cache = self.cache.write().await;
        cache.retain(|(path, _), _| path != dir_path);
    }

    /// 清空整个缓存
    pub async fn clear(&self) {
        let mut cache = self.cache.write().await;
        cache.clear();
    }
}

