pub async fn init_vfs() {
    let vfs_manager = VfsManager::builder()
        .provider(get_ext4_provider().into())
        .provider(get_devfs_provider().into())
        .build();
    vfs_manager.mount(None, "/", "ext4", Default::default()).await.unwrap();
    vfs_manager.mount(None, "/dev", "devfs", Default::default()).await.unwrap();
    // 使用 devfs 在 /proc 上提供简单的只读字符设备 /proc/interrupts
    vfs_manager.mount(None, "/proc", "devfs", Default::default()).await.unwrap();

    let dev_fs = vfs_manager.get_filesystem("/dev").await.unwrap().to_devfs().unwrap();
    dev_fs.register_char_device("serial", Arc::new(StdOutDevice), FileMode::ALL_PERMISSIONS).await.unwrap();
    dev_fs.register_char_device("null", Arc::new(NullDevice), FileMode::ALL_PERMISSIONS).await.unwrap();

    // 在 /proc 挂载的 devfs 下注册 /proc/interrupts，只读（权限给读，写入由设备返回错误）
    let proc_fs = vfs_manager.get_filesystem("/proc").await.unwrap().to_devfs().unwrap();
    proc_fs.register_char_device("interrupts", Arc::new(InterruptsDevice), FileMode::OWNER_READ | FileMode::GROUP_READ | FileMode::OTHER_READ).await.unwrap();

    VFS_MANAGER.init(vfs_manager);
}

pub fn get_path_resolver<'a>() -> PathResolver<'a> {
    let vfs_manager = VFS_MANAGER.get();
    PathResolver::new(&vfs_manager, &vfs_manager.dentry_cache, true)
}

