        let (mpath, minfo) = self.mounts.longest_match(abs)
            .await
            .ok_or_else(|| KernelError::with_message(Errno::ENOENT, "no mount"))?;
        let rest = abs.strip_prefix(PathSlice::from(&mpath))
                      .unwrap_or(PathSlice::from("."))
                      .to_owned_buf();
        Ok((mpath, minfo, rest))
    }

