pub struct VfsManagerBuilder {
    providers: Map<AString, SProvider>,
    vnode_cap: usize,
    dentry_cap: usize,
}

impl VfsManagerBuilder {
    pub fn provider(mut self, p: SProvider) -> Self {
        self.providers.insert(p.fs_type_name().into(), p); self
    }
    pub fn vnode_cache(mut self, cap: usize) -> Self { self.vnode_cap = cap; self }
    pub fn dentry_cache(mut self, cap: usize) -> Self { self.dentry_cap = cap; self }
    pub fn build(self) -> Arc<VfsManager> {
        const DFLT_VNODE: usize = 1024;
        const DFLT_DENTRY: usize = 4096;
        Arc::new_cyclic(|weak| VfsManager {
            providers: ProviderRegistry::new(self.providers),
            mounts: MountRegistry::new(),
            mount_id_pool: IdPool::new(1024),
            fs_id_pool: IdPool::new(1024),
            vnode_cache: Arc::new(VnodeCache::new(if self.vnode_cap == 0 { DFLT_VNODE } else { self.vnode_cap })),
            dentry_cache: Arc::new(DentryCache::new(if self.dentry_cap == 0 { DFLT_DENTRY } else { self.dentry_cap })),
            self_arc: weak.clone(),
        })
    }
}

pub fn provider(mut self, p: SProvider) -> Self {
        self.providers.insert(p.fs_type_name().into(), p); self
    }

pub fn build(self) -> Arc<VfsManager> {
        const DFLT_VNODE: usize = 1024;
        const DFLT_DENTRY: usize = 4096;
        Arc::new_cyclic(|weak| VfsManager {
            providers: ProviderRegistry::new(self.providers),
            mounts: MountRegistry::new(),
            mount_id_pool: IdPool::new(1024),
            fs_id_pool: IdPool::new(1024),
            vnode_cache: Arc::new(VnodeCache::new(if self.vnode_cap == 0 { DFLT_VNODE } else { self.vnode_cap })),
            dentry_cache: Arc::new(DentryCache::new(if self.dentry_cap == 0 { DFLT_DENTRY } else { self.dentry_cap })),
            self_arc: weak.clone(),
        })
    }

enum Step {
    /// 到达最终 Vnode
    Done(SVnode),
    /// 解析过程中遇到符号链接，需要以新绝对路径重启
    Restart(PathBuf),
}

pub struct PathResolver<'m> {
    mgr:        &'m crate::VfsManager,
    dcache:     &'m DentryCache,
    follow_last_symlink: bool,
    max_symlink: u32,
}

impl<'m> PathResolver<'m> {
    /// 构造
    pub const fn new(
        mgr: &'m crate::VfsManager,
        dcache: &'m DentryCache,
        follow_last_symlink: bool,
    ) -> Self {
        Self { mgr, dcache, follow_last_symlink, max_symlink: 40 }
    }

    /// 公开接口：解析绝对路径
    ///
    /// # 参数
    /// * `abs_raw` —— **必须**以 `/` 开头的 UTF‑8 字符串
    pub async fn resolve(
        &self,
        abs_path: &mut PathBuf,
    ) -> VfsResult<SVnode> {
        // 预规范化
        let todo = abs_path;
        if !todo.as_slice().is_absolute() {
            return Err(crate::vfs_err_invalid_argument!("path must be absolute"));
        }

        let mut depth = 0;
        loop {
            if depth > self.max_symlink {
                return Err(KernelError::with_message(Errno::ELOOP, "too many symlinks").into());
            }

            match self.walk_one_mount(todo.as_slice()).await? {
                Step::Done(v)      => return Ok(v),
                Step::Restart(p) => { *todo = p; depth += 1; }
            }
        }
    }

    /// 在 **单一挂载** 内遍历组件；遇到需跟随的符号链接即返回 Restart。
    async fn walk_one_mount(&self, abs: PathSlice<'_>) -> VfsResult<Step> {
        tracing::info!("abs={:?}", abs.as_str());
        // 1. 锁定挂载信息
        let (_mnt_path, mnt_info, rel) = self.mgr.locate_mount(abs).await?;
        let fs = mnt_info.fs.clone();
        let mut current = fs.root_vnode().await?;

        // 空 / 根路径直接返回（strip_prefix 根返回 "."）
        if rel.as_str() == "/" || rel.as_str() == "." || rel.as_str().is_empty() {
            return Ok(Step::Done(current));
        }

        // 2. 遍历组件
        let mut path_prefix = alloc::string::String::from(_mnt_path.as_str());   // 用于构造新绝对路径
        if !path_prefix.ends_with('/') { path_prefix.push('/'); }

        let mut comps = PathSlice::from(&rel).components().peekable();
        while let Some(seg) = comps.next() {
            let is_last = comps.peek().is_none();
            tracing::info!("prefix={:?} seg={:?} is_last={}", path_prefix, seg, is_last);
            tracing::info!("current.kind={:?}", current.metadata().await?.kind);

            // --- dentry 缓存：父目录即为当前前缀路径 ---
            let dir_key = PathSlice::from(&PathBuf::from_str_unchecked(path_prefix.clone()))
                .to_owned_buf();

            let child = if let Some(v) = self.dcache.get(&dir_key, seg).await {
                v
            } else {
                // 当前节点必须是目录；若不是，说明路径非法
                let dir = if let Some(d) = current.as_dir() {
                    d
                } else {
                    return Err(KernelError::with_message(Errno::ENOTDIR, "not a directory").into());
                };
                let v = dir.lookup(seg).await?;
                self.dcache.put(dir_key, seg, v.clone()).await;
                v
            };

            // --- 符号链接处理 ---
            if child.metadata().await?.kind == VnodeType::SymbolicLink
                && (self.follow_last_symlink || !is_last)
            {
                let target = child.as_symlink().unwrap().readlink().await?; // 可能是绝对或相对
                // 1. 绝对：直接替换
                // 2. 相对：基于 path_prefix 构造
                let mut new_abs = if PathSlice::from(&target).is_absolute() {
                    target
                } else {
                    let mut s = path_prefix.clone();           // 已含到当前目录
                    s.push_str(target.as_str());
                    PathBuf::new(s)?
                };

                // 将 comps 剩余部分附在尾部
                for rest in comps {
                    new_abs = PathSlice::from(&new_abs).join(rest)?;
                }
                return Ok(Step::Restart(new_abs));
            }

            // 前进
            current = child;
            if !path_prefix.ends_with('/') { path_prefix.push('/'); }
            path_prefix.push_str(seg);
        }
        Ok(Step::Done(current))
    }
}

