impl PipeWriter {
    pub async fn write_at(&self, _ofs: u64, src: &[u8]) -> VfsResult<usize> {
        {
            let mut b = self.0.buf.lock().await;
            for &c in src {
                b.push_back(c);
            }
        }
        // 唤醒可能阻塞的读端
        self.0.notify.wake();
        Ok(src.len())
    }
}

