impl Drop for PipeWriter {
    fn drop(&mut self) {
        // 写端计数减少，可能已有读端在等待；
        // 释放锁同步不必等待，因此直接唤醒一次。
        // 此时唤醒时，还会继续运行当前的线程（在当前调度器和调度策略下），因此其他线程看到的计数会减少。
        self.0.notify.wake();
    }
}

