impl AsyncCharDevice for InterruptsDevice {
    async fn read(&self, off: u64, buf: &mut [u8]) -> VfsResult<usize> {
        // 取一次快照并编码为文本
        let mut s = String::new();
        for (irq, cnt) in ostd::interrupts::snapshot() {
            // 任意空格数量均可，测试使用“%u: %u”解析
            let _ = core::fmt::Write::write_str(&mut s, &format!("{irq}:        {cnt}\n"));
        }
        let bytes = s.as_bytes();
        let start = core::cmp::min(off as usize, bytes.len());
        let end = core::cmp::min(start + buf.len(), bytes.len());
        let n = end - start;
        buf[..n].copy_from_slice(&bytes[start..end]);
        Ok(n)
    }
    // 写入保持默认 ENODEV（不支持写），满足测例“不可写”要求
}

