        flags: OpenFlags,
    ) -> VfsResult<Arc<dyn crate::traits::AsyncFileHandle + Send + Sync>> {
        match &self.kind {
            InMemoryVnodeKindData::File(_) => {
                Ok(Arc::new(super::handle::InMemoryFileHandle::new(self.clone(), flags)) as Arc<_>)
            }
