struct TimespecNs {
    tv_sec: i64,
    tv_nsec: i64,
}

pub async fn do_clock_gettime(
    state: &mut ThreadState,
    uc: &mut ostd::cpu::UserContext,
) -> Result<ControlFlow<i32, Option<isize>>> {
    let [which, tp_ptr, ..] = uc.syscall_arguments();
    if tp_ptr == 0 {
        return Err(errno_with_message(Errno::EFAULT, "null timespec pointer"));
    }
    match which as i32 {
        0 | 1 => {
            let d = duration_since_boot();
            let ts = TimespecNs {
                tv_sec: d.as_secs() as i64,
                tv_nsec: d.subsec_nanos() as i64,
            };
            state.process_vm.write_val(tp_ptr as _, &ts)?;
            Ok(ControlFlow::Continue(Some(0)))
        }
        _ => Err(errno_with_message(Errno::EINVAL, "unsupported clock id")),
    }
}

