pub extern "C" fn riscv_boot(hart_id: usize, device_tree_paddr: usize) -> ! {
    crate::early_println!(
        "riscv_boot: hart_id = {}, device_tree_paddr = {}",
        hart_id,
        device_tree_paddr
    );
    // 第一个执行此函数的 hart 将成为 BSP
    let bsp_hart_id = *BSP_HART_ID.call_once(|| hart_id);

    if hart_id == bsp_hart_id {
        let device_tree_ptr = paddr_to_vaddr(device_tree_paddr) as *const u8;
        // 安全性：DTB 指针由引导程序/SBI 提供给第一个 hart（BSP）
        let fdt = unsafe { fdt::Fdt::from_ptr(device_tree_ptr).unwrap() };

        // 由于 BSP 是第一个调用者，这应该会成功
        DEVICE_TREE.call_once(|| fdt);

        use crate::boot::{call_ostd_main, EarlyBootInfo, EARLY_INFO};

        // 安全性：此函数仅由 BSP 调用一次
        EARLY_INFO.call_once(|| {
            EarlyBootInfo {
                bootloader_name: parse_bootloader_name(),
                kernel_cmdline: parse_kernel_commandline(),
                initramfs: parse_initramfs(),
                acpi_arg: parse_acpi_arg(),
                framebuffer_arg: parse_framebuffer_info(),
                memory_regions: parse_memory_regions(),
            }
        });

        call_ostd_main();
    } else {
        // 当前 hart 是 AP
        crate::boot::smp::ap_early_entry(hart_id as u32);
    }
}

pub(crate) fn get_num_processors() -> Option<u32> {
    // 从 BSP 初始化时存储的 DEVICE_TREE 获取 Fdt 对象
    let fdt = DEVICE_TREE.get()?;

    // 查找 /cpus 节点
    let cpus_node = fdt.find_node("/cpus")?;

    // 计算 /cpus 节点下类型为 "cpu" 的子节点数量
    let num_cpus = cpus_node
        .children()
        .filter(|child| match child.property("device_type") {
            Some(prop) => prop.as_str().map_or(false, |s| s == "cpu"),
            None => false,
        })
        .count();

    if num_cpus > 0 {
        Some(num_cpus as u32)
    } else {
        // 如果找不到 cpu 子节点，可能 DTB 结构不同，或者只有 BSP
        // 尝试直接读取 /cpus 下的 #size-cells 和 #address-cells？或者返回 1？
        // 暂时返回 1 作为保底，表示至少有 BSP。
        log::warn!("Could not determine number of CPUs from DTB, assuming 1 (BSP only).");
        Some(1) // 保底返回 1
    }
}

pub(crate) fn bringup_all_aps(bsp_hart_id: u32) {
    let Some(num_processors) = get_num_processors() else {
        log::warn!("Cannot get number of processors, skipping AP bringup.");
        return;
    };

    let ap_count = num_processors - 1;
    if ap_count == 0 {
        log::info!(
            "Only one processor found (BSP {}), no APs to bring up.",
            bsp_hart_id
        );
        return;
    }

    // 获取 _start 的物理地址。
    // 具体详见 osdk/src/base_crate/riscv64.ld.template
    let start_addr_phys = _start_ap as usize - kernel_loaded_offset();

    log::info!(
        "Attempting to bring up {} AP(s) starting at P:{:#x}...",
        ap_count,
        start_addr_phys
    );

    // Get the AP boot info which contains the stack pointers
    let ap_boot_info = AP_BOOT_INFO
        .get()
        .expect("AP_BOOT_INFO not initialized before bringup_all_aps");
    let stack_array_ptr =
        crate::mm::paddr_to_vaddr(ap_boot_info.boot_stack_array.start_paddr()) as *const u64;

    // Iterate through all potential hart IDs.
    for hart_id in 0..num_processors {
        // Skip the BSP itself.
        if hart_id == bsp_hart_id {
            continue;
        }

        // Read the pre-allocated stack pointer for this AP from the array
        // SAFETY: The pointer is valid, aligned, and initialized by boot_all_aps.
        // We assume hart_id < 1024 based on the array size in boot_all_aps.
        let ap_stack_pointer = unsafe { stack_array_ptr.add(hart_id as usize).read_volatile() };

        if ap_stack_pointer == 0 {
            log::error!("Stack pointer for hart {} is zero! Skipping.", hart_id);
            continue;
        }

        log::debug!(
            "AP {}: Read stack pointer {:#x} from array index {}",
            hart_id,
            ap_stack_pointer,
            hart_id
        );

        // 使用 SBI 调用唤醒 AP，将栈顶指针作为 opaque 参数传递
        log::debug!(
            "Sending SBI hart_start to hart {} at P:{:#x} with SP:{:#x}",
            hart_id,
            start_addr_phys,
            ap_stack_pointer
        );
        let ret = sbi_rt::hart_start(hart_id as usize, start_addr_phys, ap_stack_pointer as usize);

        if ret.is_err() {
            log::error!(
                "Failed to start hart {} with physical address {:#x} and SP {:#x}. SBI Error: {:?}",
                hart_id,
                start_addr_phys,
                ap_stack_pointer,
                ret.err().unwrap()
            );
        } else {
            log::debug!(
                "SBI hart_start call seemingly succeeded for hart {}.",
                hart_id
            );
        }
    }

    // 注意：sbi_rt::hart_start 只是发送启动请求，AP 可能不会立即启动。
    // BSP 会在稍后调用 wait_for_all_aps_started() (在通用 smp 模块中) 来确认 AP 是否已成功初始化。
}

pub(crate) fn get_num_processors() -> Option<u32> {
    if !ACPI_TABLES.is_completed() {
        return None;
    }
    let processor_info = PlatformInfo::new(&*ACPI_TABLES.get().unwrap().lock())
        .unwrap()
        .processor_info
        .unwrap();
    Some(processor_info.application_processors.len() as u32 + 1)
}

pub(crate) fn bringup_all_aps() {
    copy_ap_boot_code();
    fill_boot_stack_array_ptr();
    fill_boot_pt_ptr();
    send_boot_ipis();
}

pub(super) fn ap_boot_code_size() -> usize {
    __ap_boot_end as usize - __ap_boot_start as usize
}

fn copy_ap_boot_code() {
    let ap_boot_start = __ap_boot_start as usize as *const u8;
    let len = __ap_boot_end as usize - __ap_boot_start as usize;

    // SAFETY: we are copying the AP boot code to the AP boot address.
    unsafe {
        core::ptr::copy_nonoverlapping(
            ap_boot_start,
            crate::mm::paddr_to_vaddr(AP_BOOT_START_PA) as *mut u8,
            len,
        );
    }
}

fn fill_boot_stack_array_ptr() {
    let pages = &crate::boot::smp::AP_BOOT_INFO
        .get()
        .unwrap()
        .boot_stack_array;

    extern "C" {
        static __ap_boot_stack_array_pointer: u64;
    }

    // SAFETY: This pointer points to a static variable defined in the `ap_boot.S`.
    let ptr = unsafe { &__ap_boot_stack_array_pointer as *const u64 as *mut u64 };
    // SAFETY: We only write to it once.
    unsafe {
        ptr.write_volatile(paddr_to_vaddr(pages.start_paddr()) as u64);
    }
}

fn fill_boot_pt_ptr() {
    extern "C" {
        static __boot_page_table_pointer: u32;
    }
    let boot_pt = crate::mm::page_table::boot_pt::with_borrow(|pt| pt.root_address()).unwrap();

    // SAFETY: this pointer points to a static variable defined in the `ap_boot.S`.
    let ptr = unsafe { &__boot_page_table_pointer as *const u32 as *mut u32 };
    // SAFETY: We only write to it once.
    unsafe {
        ptr.write_volatile(boot_pt as u32);
    }
}

fn send_boot_ipis() {
    send_init_to_all_aps();

    spin_wait_cycles(100_000_000);

    send_init_deassert();

    spin_wait_cycles(20_000_000);

    send_startup_to_all_aps();

    spin_wait_cycles(20_000_000);

    send_startup_to_all_aps();

    spin_wait_cycles(20_000_000);
}

fn send_startup_to_all_aps() {
    let icr = Icr::new(
        ApicId::from(0),
        DestinationShorthand::AllExcludingSelf,
        TriggerMode::Edge,
        Level::Assert,
        DeliveryStatus::Idle,
        DestinationMode::Physical,
        DeliveryMode::StartUp,
        (AP_BOOT_START_PA / PAGE_SIZE) as u8,
    );
    // SAFETY: we are sending startup IPI to all APs.
    apic::with_borrow(|apic| unsafe { apic.send_ipi(icr) });
}

fn send_init_to_all_aps() {
    let icr = Icr::new(
        ApicId::from(0),
        DestinationShorthand::AllExcludingSelf,
        TriggerMode::Level,
        Level::Assert,
        DeliveryStatus::Idle,
        DestinationMode::Physical,
        DeliveryMode::Init,
        0,
    );
    // SAFETY: we are sending init IPI to all APs.
    apic::with_borrow(|apic| unsafe { apic.send_ipi(icr) });
}

fn send_init_deassert() {
    let icr = Icr::new(
        ApicId::from(0),
        DestinationShorthand::AllIncludingSelf,
        TriggerMode::Level,
        Level::Deassert,
        DeliveryStatus::Idle,
        DestinationMode::Physical,
        DeliveryMode::Init,
        0,
    );
    // SAFETY: we are sending deassert IPI to all APs.
    apic::with_borrow(|apic| unsafe { apic.send_ipi(icr) });
}

fn spin_wait_cycles(c: u64) {
    fn duration(from: u64, to: u64) -> u64 {
        if to >= from {
            to - from
        } else {
            u64::MAX - from + to
        }
    }

    use core::arch::x86_64::_rdtsc;

    let start = unsafe { _rdtsc() };

    while duration(start, unsafe { _rdtsc() }) < c {
        core::hint::spin_loop();
    }
}

fn duration(from: u64, to: u64) -> u64 {
        if to >= from {
            to - from
        } else {
            u64::MAX - from + to
        }
    }

fn parse_kernel_commandline(boot_params: &BootParams) -> &str {
    // SAFETY: The pointer in the header points to a valid C string.
    let cmdline_c_str: &CStr = unsafe { CStr::from_ptr(boot_params.hdr.cmd_line_ptr as *const i8) };
    let cmdline_str = cmdline_c_str.to_str().unwrap();
    cmdline_str
}

fn parse_initramfs(boot_params: &BootParams) -> Option<&[u8]> {
    let hdr = &boot_params.hdr;
    let ptr = hdr.ramdisk_image as usize;
    if ptr == 0 {
        return None;
    }
    // We must return a slice composed by VA since kernel should read everything in VA.
    let base_va = if ptr < LINEAR_MAPPING_BASE_VADDR {
        paddr_to_vaddr(ptr)
    } else {
        ptr
    };
    let length = hdr.ramdisk_size as usize;
    if length == 0 {
        return None;
    }
    // SAFETY: The regions is reported as initramfs by the bootloader, so it should be valid.
    Some(unsafe { core::slice::from_raw_parts(base_va as *const u8, length) })
}

fn parse_acpi_arg(boot_params: &BootParams) -> BootloaderAcpiArg {
    let rsdp = boot_params.acpi_rsdp_addr;
    if rsdp == 0 {
        BootloaderAcpiArg::NotProvided
    } else {
        BootloaderAcpiArg::Rsdp(rsdp.try_into().expect("RSDP address overflowed!"))
    }
}

fn parse_framebuffer_info(boot_params: &BootParams) -> Option<BootloaderFramebufferArg> {
    let screen_info = boot_params.screen_info;
    if screen_info.lfb_base == 0 {
        return None;
    }
    Some(BootloaderFramebufferArg {
        address: screen_info.lfb_base as usize,
        width: screen_info.lfb_width as usize,
        height: screen_info.lfb_height as usize,
        bpp: screen_info.lfb_depth as usize,
    })
}

impl From<E820Type> for MemoryRegionType {
    fn from(value: E820Type) -> Self {
        match value {
            E820Type::Ram => Self::Usable,
            E820Type::Reserved => Self::Reserved,
            E820Type::Acpi => Self::Reclaimable,
            E820Type::Nvs => Self::NonVolatileSleep,
            _ => Self::BadMemory,
        }
    }
}

fn from(value: E820Type) -> Self {
        match value {
            E820Type::Ram => Self::Usable,
            E820Type::Reserved => Self::Reserved,
            E820Type::Acpi => Self::Reclaimable,
            E820Type::Nvs => Self::NonVolatileSleep,
            _ => Self::BadMemory,
        }
    }

fn parse_memory_regions(boot_params: &BootParams) -> MemoryRegionArray {
    let mut regions = MemoryRegionArray::new();

    // Add regions from E820.
    let num_entries = boot_params.e820_entries as usize;
    for e820_entry in &boot_params.e820_table[0..num_entries] {
        regions
            .push(MemoryRegion::new(
                e820_entry.addr as usize,
                e820_entry.size as usize,
                e820_entry.typ.into(),
            ))
            .unwrap();
    }

    // Add the kernel region.
    regions.push(MemoryRegion::kernel()).unwrap();

    // Add the initramfs region.
    regions
        .push(MemoryRegion::new(
            boot_params.hdr.ramdisk_image as usize,
            boot_params.hdr.ramdisk_size as usize,
            MemoryRegionType::Module,
        ))
        .unwrap();

    // Add the AP boot code region that will be copied into by the BSP.
    regions
        .push(MemoryRegion::new(
            super::smp::AP_BOOT_START_PA,
            super::smp::ap_boot_code_size(),
            MemoryRegionType::Reclaimable,
        ))
        .unwrap();

    regions.into_non_overlapping()
}

unsafe extern "sysv64" fn __linux_boot(params_ptr: *const BootParams) -> ! {
    let params = unsafe { &*params_ptr };
    assert_eq!({ params.hdr.header }, LINUX_BOOT_HEADER_MAGIC);

    use crate::boot::{call_ostd_main, EarlyBootInfo, EARLY_INFO};

    EARLY_INFO.call_once(|| EarlyBootInfo {
        bootloader_name: parse_bootloader_name(params),
        kernel_cmdline: parse_kernel_commandline(params),
        initramfs: parse_initramfs(params),
        acpi_arg: parse_acpi_arg(params),
        framebuffer_arg: parse_framebuffer_info(params),
        memory_regions: parse_memory_regions(params),
    });

    call_ostd_main();
}

fn parse_bootloader_name(mb1_info: &MultibootLegacyInfo) -> &str {
    let mut name = "Unknown Multiboot loader";
    if mb1_info.boot_loader_name != 0 {
        // SAFETY: the bootloader name is C-style zero-terminated string.
        unsafe {
            let cstr = paddr_to_vaddr(mb1_info.boot_loader_name as usize) as *const u8;
            let mut len = 0;
            while cstr.add(len).read() != 0 {
                len += 1;
            }

            name = core::str::from_utf8(core::slice::from_raw_parts(cstr, len))
                .expect("cmdline is not a utf-8 string");
        }
    }
    name
}

fn parse_kernel_commandline(mb1_info: &MultibootLegacyInfo) -> &str {
    let mut cmdline = "";
    if mb1_info.cmdline != 0 {
        let ptr = paddr_to_vaddr(mb1_info.cmdline as usize) as *const i8;
        // SAFETY: the command line is C-style zero-terminated string.
        let cstr = unsafe { core::ffi::CStr::from_ptr(ptr) };
        cmdline = cstr.to_str().unwrap();
    }
    cmdline
}

fn parse_initramfs(mb1_info: &MultibootLegacyInfo) -> Option<&[u8]> {
    // FIXME: We think all modules are initramfs, can this cause problems?
    if mb1_info.mods_count == 0 {
        return None;
    }
    let modules_addr = mb1_info.mods_addr as usize;
    // We only use one module
    let (start, end) = unsafe {
        (
            (*(paddr_to_vaddr(modules_addr) as *const u32)) as usize,
            (*(paddr_to_vaddr(modules_addr + 4) as *const u32)) as usize,
        )
    };
    // We must return a slice composed by VA since kernel should read every in VA.
    let base_va = if start < LINEAR_MAPPING_BASE_VADDR {
        paddr_to_vaddr(start)
    } else {
        start
    };
    let length = end - start;

    Some(unsafe { core::slice::from_raw_parts(base_va as *const u8, length) })
}

fn parse_acpi_arg(_mb1_info: &MultibootLegacyInfo) -> BootloaderAcpiArg {
    // The multiboot protocol does not contain RSDP address.
    // TODO: What about UEFI?
    BootloaderAcpiArg::NotProvided
}

fn parse_framebuffer_info(mb1_info: &MultibootLegacyInfo) -> Option<BootloaderFramebufferArg> {
    if mb1_info.framebuffer_table.addr == 0 {
        return None;
    }
    Some(BootloaderFramebufferArg {
        address: mb1_info.framebuffer_table.addr as usize,
        width: mb1_info.framebuffer_table.width as usize,
        height: mb1_info.framebuffer_table.height as usize,
        bpp: mb1_info.framebuffer_table.bpp as usize,
    })
}

fn parse_memory_regions(mb1_info: &MultibootLegacyInfo) -> MemoryRegionArray {
    let mut regions = MemoryRegionArray::new();

    // Add the regions in the multiboot protocol.
    for entry in mb1_info.get_memory_map() {
        let start = entry.base_addr();
        let region = MemoryRegion::new(
            start.try_into().unwrap(),
            entry.length().try_into().unwrap(),
            entry.memory_type(),
        );
        regions.push(region).unwrap();
    }

    // Add the framebuffer region.
    let fb = BootloaderFramebufferArg {
        address: mb1_info.framebuffer_table.addr as usize,
        width: mb1_info.framebuffer_table.width as usize,
        height: mb1_info.framebuffer_table.height as usize,
        bpp: mb1_info.framebuffer_table.bpp as usize,
    };
    regions
        .push(MemoryRegion::new(
            fb.address,
            (fb.width * fb.height * fb.bpp).div_ceil(8), // round up when divide with 8 (bits/Byte)
            MemoryRegionType::Framebuffer,
        ))
        .unwrap();

    // Add the kernel region.
    regions.push(MemoryRegion::kernel()).unwrap();

    // Add the initramfs area.
    if mb1_info.mods_count != 0 {
        let modules_addr = mb1_info.mods_addr as usize;
        // We only use one module
        let (start, end) = unsafe {
            (
                (*(paddr_to_vaddr(modules_addr) as *const u32)) as usize,
                (*(paddr_to_vaddr(modules_addr + 4) as *const u32)) as usize,
            )
        };
        regions
            .push(MemoryRegion::new(
                start,
                end - start,
                MemoryRegionType::Module,
            ))
            .unwrap();
    }

    // Add the AP boot code region that will be copied into by the BSP.
    regions
        .push(MemoryRegion::new(
            super::smp::AP_BOOT_START_PA,
            super::smp::ap_boot_code_size(),
            MemoryRegionType::Reclaimable,
        ))
        .unwrap();

    regions.into_non_overlapping()
}

struct MultibootLegacyInfo {
    /// Indicate whether the below field exists.
    flags: u32,

    /// Physical memory low.
    mem_lower: u32,
    /// Physical memory high.
    mem_upper: u32,

    /// Indicates which BIOS disk device the boot loader loaded the OS image from.
    boot_device: u32,

    /// Command line passed to kernel.
    cmdline: u32,

    /// Modules count.
    mods_count: u32,
    /// The start address of modules list, each module structure format:
    /// ```text
    ///         +-------------------+
    /// 0       | mod_start         |
    /// 4       | mod_end           |
    ///         +-------------------+
    /// 8       | string            |
    ///         +-------------------+
    /// 12      | reserved (0)      |
    ///         +-------------------+
    /// ```
    mods_addr: u32,

    /// If flags[4] = 1, then the field starting at byte 28 are valid:
    /// ```text
    ///         +-------------------+
    /// 28      | tabsize           |
    /// 32      | strsize           |
    /// 36      | addr              |
    /// 40      | reserved (0)      |
    ///         +-------------------+
    /// ```
    /// These indicate where the symbol table from kernel image can be found.
    ///
    /// If flags[5] = 1, then the field starting at byte 28 are valid:
    /// ```text
    ///         +-------------------+
    /// 28      | num               |
    /// 32      | size              |
    /// 36      | addr              |
    /// 40      | shndx             |
    ///         +-------------------+
    /// ```
    /// These indicate where the section header table from an ELF kernel is,
    /// the size of each entry, number of entries, and the string table used as the index of names.
    symbols: [u8; 16],

    memory_map_len: u32,
    memory_map_addr: u32,

    drives_length: u32,
    drives_addr: u32,

    config_table: u32,

    boot_loader_name: u32,

    apm_table: u32,

    vbe_table: VbeTable,

    framebuffer_table: FramebufferTable,
}

impl MultibootLegacyInfo {
    fn get_memory_map(&self) -> MemoryEntryIter {
        let ptr = self.memory_map_addr as Paddr;
        let end = ptr + self.memory_map_len as usize;
        MemoryEntryIter {
            cur_ptr: paddr_to_vaddr(ptr),
            region_end: paddr_to_vaddr(end),
        }
    }
}

fn get_memory_map(&self) -> MemoryEntryIter {
        let ptr = self.memory_map_addr as Paddr;
        let end = ptr + self.memory_map_len as usize;
        MemoryEntryIter {
            cur_ptr: paddr_to_vaddr(ptr),
            region_end: paddr_to_vaddr(end),
        }
    }

struct MemoryEntry {
    ptr: Vaddr,
}

impl MemoryEntry {
    fn size(&self) -> u32 {
        // SAFETY: the entry can only be constructed from a valid address.
        unsafe { (self.ptr as *const u32).read_unaligned() }
    }

    fn base_addr(&self) -> u64 {
        // SAFETY: the entry can only be constructed from a valid address.
        unsafe { ((self.ptr + 4) as *const u64).read_unaligned() }
    }

    fn length(&self) -> u64 {
        // SAFETY: the entry can only be constructed from a valid address.
        unsafe { ((self.ptr + 12) as *const u64).read_unaligned() }
    }

    fn memory_type(&self) -> MemoryRegionType {
        // The multiboot (v1) manual doesn't specify the length of the type field.
        // Experimental result shows that "u8" works. So be it.
        // SAFETY: the entry can only be constructed from a valid address.
        let typ_val = unsafe { ((self.ptr + 20) as *const u8).read_unaligned() };
        // The meaning of the values are however documented clearly by the manual.
        match typ_val {
            1 => MemoryRegionType::Usable,
            2 => MemoryRegionType::Reserved,
            3 => MemoryRegionType::Reclaimable,
            4 => MemoryRegionType::NonVolatileSleep,
            5 => MemoryRegionType::BadMemory,
            _ => MemoryRegionType::Reserved,
        }
    }
}

