fn drop(&mut self) {
        unsafe {
            let ptr = IRQ_TABLE[self.irq_num as usize].load(Ordering::Acquire);
            if !ptr.is_null() {
                (*ptr)
                    .callback_list
                    .lock()
                    .retain(|item| item.id != self.id);
            }
        }
        CALLBACK_ID_ALLOCATOR.get().unwrap().lock().free(self.id);
    }

pub enum IpiSendError {
    /// 目标 CPU 的 IPI 命令队列已满
    QueueFull,
    /// 底层 SBI send_ipi 调用失败
    SbiError(sbi_spec::binary::Error),
}

impl From<sbi_spec::binary::Error> for IpiSendError {
    fn from(err: sbi_spec::binary::Error) -> Self {
        IpiSendError::SbiError(err)
    }
}

fn from(err: sbi_spec::binary::Error) -> Self {
        IpiSendError::SbiError(err)
    }

pub(crate) unsafe fn send_ipi(cpu_id: CpuId, irq_num: IrqNum) -> Result<(), IpiSendError> {
    let hart_id = cpu_id.as_usize();
    crate::early_println!("send_ipi: send IPI to CPU {}", hart_id);

    let queue = CPU_IPI_QUEUES
        .get_on_cpu(cpu_id)
        .get()
        .expect("CPU_IPI_QUEUES is not initialized");

    queue.push(irq_num).map_err(|_| IpiSendError::QueueFull)?;

    sbi_rt::send_ipi(build_hart_mask(hart_id))
        .into_result()
        .inspect_err(|e| {
            log::error!(
                "send_ipi: send IPI to CPU {} failed, SBI error: {:?}",
                hart_id,
                e
            );
        })?;
    Ok(())
}

fn build_hart_mask(hart_id: usize) -> sbi_rt::HartMask {
    let (base, mask) = ((hart_id / 32) * 32, 1 << (hart_id % 32));
    sbi_rt::HartMask::from_mask_base(mask, base)
}

pub(crate) fn init() {
    let mut list: Vec<IrqLine> = Vec::new();
    for i in 0..256 {
        list.push(IrqLine {
            irq_num: i as u8,
            callback_list: RwLock::new(Vec::new()),
            bind_remapping_entry: Once::new(),
        });
    }
    IRQ_LIST.call_once(|| list);
    CALLBACK_ID_ALLOCATOR.call_once(|| Mutex::new(IdAlloc::with_capacity(256)));
    IRQ_ALLOCATOR.call_once(|| {
        // As noted in the Intel 64 and IA-32 rchitectures Software Developer’s Manual,
        // Volume 3A, Section 6.2, the first 32 interrupts are reserved for specific
        // usages. And the rest from 32 to 255 are available for external user-defined
        // interrupts.
        let mut id_alloc = IdAlloc::with_capacity(256);
        for i in 0..32 {
            id_alloc.alloc_specific(i).unwrap();
        }
        SpinLock::new(id_alloc)
    });
}

pub(crate) fn enable_local() {
    x86_64::instructions::interrupts::enable();
    // When emulated with QEMU, interrupts may not be delivered if a STI instruction is immediately
    // followed by a RET instruction. It is a BUG of QEMU, see the following patch for details.
    // https://lore.kernel.org/qemu-devel/20231210190147.129734-2-lrh2000@pku.edu.cn/
    x86_64::instructions::nop();
}

pub(crate) fn disable_local() {
    x86_64::instructions::interrupts::disable();
}

pub(crate) fn is_local_enabled() -> bool {
    (rflags::read_raw() & RFlags::INTERRUPT_FLAG.bits()) != 0
}

