fn test_sizes() {
        #[cfg(linux_kernel)]
        assert_eq_size!(c::loff_t, u64);

        // Assert that `Timestamps` has the expected layout. If we're not fixing
        // y2038, libc's type should match ours. If we are, it's smaller.
        #[cfg(not(fix_y2038))]
        assert_eq_size!([c::timespec; 2], Timestamps);
